"""
MKT Christ Commentary — Nehemiah chapters 7–8
Run: python3 scripts/zc-christ-nehemiah-7-8.py

Source data used:
- data/interlinear/nehemiah.json
- data/translation/draft/mediating/nehemiah.json

Key decisions in this range:
- Ch7 is a census list (73 verses); list entries receive brief thematic readings
  connecting the recorded names to the Lamb's book of life (Rev 21:27; Luke 10:20)
- 7:63-65 (priestly genealogical uncertainty) receives fuller treatment — points
  to Christ as the definitive priest who validates by divine oath, not genealogy
- Ch8 (Torah reading) is the theological climax: Ezra reads/explains = type of
  Christ who both is the Word and opens minds to understand Scripture
- 8:10 "joy of the LORD is your strength" — the reversal from weeping to joy = gospel pattern
- 8:14-18 Feast of Booths rediscovered → John 7:37-38 (Jesus at Tabernacles)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEHEMIAH = {
  "7": {
    "1": '<p>A theme: the appointment of gatekeepers, singers, and Levites immediately after the wall&#8217;s completion establishes that the wall exists to protect worship rather than to project power. The pattern anticipates Christ as the gate of the sheepfold (John 10:9): the true wall-gate is not architectural but personal — the one who gives access to the Father and keeps the flock safe from the adversary who would enter by another way.</p>',
    "2": '<p>A theme: Hananiah is appointed because he was &#8220;more faithful and God-fearing than most&#8221; — character, not merely office, qualifies for responsibility over the holy city. The NT applies the same criterion to those entrusted with Christ&#8217;s people: &#8220;It is required that those who have been given a trust must prove faithful&#8221; (1 Cor 4:2). Nehemiah&#8217;s appointment anticipates the qualifications for Christian leadership that Paul specifies (1 Tim 3:2-7).</p>',
    "3": '<p>A theme: &#8220;Do not open the gates until the sun is high&#8221; — vigilance about access to Jerusalem; the gate as the controlled boundary between the protected city and the dangerous outside. Christ describes the narrow gate (Matt 7:13-14) and himself as the gate (John 10:9) through which alone the sheep enter safely; the Nehemiah gate-protocol is a shadow of the exclusivity and security of access through Christ.</p>',
    "4": '<p>A theme: the city large but sparsely populated — the wall rebuilt before the city is filled; the infrastructure of the covenant community precedes its full population. This provisional completion anticipates the NT&#8217;s eschatological framing: the church is the gathered community still awaiting its complete number (Rev 6:11); the city is built and the gates are open, but it is not yet full.</p>',
    "5": '<p>A theme: &#8220;My God put it into my heart&#8221; — divine prompting for the genealogical register; the same phrase as 2:12 (God put the wall-building into Nehemiah&#8217;s heart). The divine prompting to record those who belong to the covenant community is the shadow of God&#8217;s sovereign maintenance of the Lamb&#8217;s book of life (Rev 21:27); the census is YHWH&#8217;s act, not merely an administrative convenience.</p>',
    "6": '<p>A theme: &#8220;These are the people of the province who came up from the captivity of the exiles&#8221; — the preamble to the census identifies the community as those gathered from exile according to YHWH&#8217;s promise (Deut 30:4). Every individual listed in the census represents a divine act of gathering; the return from Babylon is the partial fulfillment of the promise that would be completely fulfilled when Christ gathers his people from every nation (John 11:52; Eph 1:10).</p>',
    "7": '<p>A theme: twelve leaders head the return — Zerubbabel, Jeshua, Nehemiah, Azariah, Raamiah, Nahamani, Mordecai, Bilshan, Mispereth, Bigvai, Nehum, and Baanah — twelve names echoing the twelve tribes of the original exodus. The twelve-leader structure is the first return&#8217;s formal correspondence to the twelve patriarchs; Jesus will reconstitute Israel&#8217;s leadership around twelve apostles (Matt 10:1-4), the new heads of the reconstituted people of God.</p>',
    "8": '<p>A theme: the descendants of Parosh numbered 2,172 — each name in the census represents one for whom YHWH kept his gather-clause promise (Neh 1:9). Luke 10:20 reframes this kind of accounting: &#8220;Rejoice that your names are written in heaven&#8221;; the genealogical registration that Nehemiah is compiling is the earthly shadow of the divine register of those who belong to Christ.</p>',
    "9": '<p>A theme: the descendants of Shephatiah, 372 — each clan&#8217;s return constitutes evidence of YHWH&#8217;s fidelity across the exile. The covenant that seemed broken by the destruction of Jerusalem was maintained through the preservation of these families; Paul&#8217;s declaration &#8220;If we are faithless, he remains faithful — for he cannot deny himself&#8221; (2 Tim 2:13) describes the same divine characteristic that the census list demonstrates.</p>',
    "10": '<p>A theme: the descendants of Arah, 652 — the Arah family appears in Ezra 2:5 (775 returned) and here 652; the difference may reflect deaths, further relocations, or counting adjustments; such discrepancies within the canonical text testify to the historical particularity of the list. Each name is a particular human life recovered from the nations by YHWH, anticipating Paul&#8217;s declaration that Christ&#8217;s purpose was to &#8220;bring all things in heaven and on earth together under one head, even Christ&#8221; (Eph 1:10).</p>',
    "11": '<p>A theme: the descendants of Pahath-moab, 2,818 — a large clan whose very name (&#8220;governor of Moab&#8221;) hints at an ancestry connected to Moabite territory. Their inclusion in the covenant census points forward to the inclusion of all nations in the people of God; Ruth the Moabite is in Bethlehem&#8217;s census (Matt 1:5), and Moab&#8217;s descendants are in the return list — the boundary is covenant orientation, not ethnic origin.</p>',
    "12": '<p>A theme: the descendants of Elam, 1,254 — the same count as Ezra 2:7; Elam was a territory northeast of Babylon. Their preservation through exile and return reflects the divine promise that YHWH will gather his people from &#8220;the far ends of the heavens&#8221; (Neh 1:9). The NT fulfillment: Elamites are explicitly present at Pentecost (Acts 2:9) — the people YHWH brought back from Elam&#8217;s territory hear the gospel on the day the Spirit is poured out.</p>',
    "13": '<p>A theme: the descendants of Zattu, 845 — each clan&#8217;s inclusion signals the breadth of the return. The census&#8217;s detailed preservation of smaller family counts reflects the OT&#8217;s consistent pattern of particularity: YHWH knows his people by name and number, a pattern that reaches its NT expression in Christ&#8217;s declaration that &#8220;the very hairs of your head are all numbered&#8221; (Matt 10:30) and the shepherd&#8217;s knowledge of each sheep (John 10:14).</p>',
    "14": '<p>A theme: the descendants of Zaccai, 760 — the name means &#8220;pure&#8221; or &#8220;innocent.&#8221; The covenant community is characterized not by their own purity (the confession of ch9 will be clear about that) but by their inclusion in the covenant established on divine mercy; this is the community whose purity is imputed through YHWH&#8217;s election, anticipating the NT&#8217;s declaration that we are &#8220;holy and blameless in his sight&#8221; through Christ (Eph 1:4).</p>',
    "15": '<p>A theme: the descendants of Binnui, 648 — the Binnui family is Levitical (v.43; Neh 12:8); the same family name appears across multiple lists. The continuity of named families across two generations (Ezra&#8217;s return + Nehemiah&#8217;s census) demonstrates the institutional preservation of the covenant community through the exile — the same faithfulness that maintains the NT church across generations of persecution and dispersal.</p>',
    "16": '<p>A theme: the descendants of Bebai, 628 — one of the smaller clans, preserved in the census alongside the great families like Parosh and Pahath-moab. The inclusion of smaller clans alongside larger ones reflects the covenant principle that size does not determine worth; the same principle governs the NT community where &#8220;God chose the weak things of the world to shame the strong&#8221; (1 Cor 1:27).</p>',
    "17": '<p>A theme: the descendants of Azgad, 2,322 — one of the largest clans; in Ezra 2:12 they numbered 1,222, suggesting significant growth or a different counting method. The census registers the community at a particular historical moment; the NT&#8217;s corresponding registration is of those whose names are in the Lamb&#8217;s book of life (Rev 21:27) — a register not subject to revision or discrepancy.</p>',
    "18": '<p>A theme: the descendants of Adonikam, 667 — the name means &#8220;my lord has arisen.&#8221; The theophoric element in many personal names throughout this census (YHWH-names, El-names) testifies to the covenant community&#8217;s persistent naming of children after the God of Israel across the exile; the names embody the faith that was maintained despite the catastrophe, anticipating the NT community&#8217;s identity as those who are named after Christ (Acts 11:26; 1 Pet 4:16).</p>',
    "19": '<p>A theme: the descendants of Bigvai, 2,067 — a Persian name within the Israelite census, reflecting the cultural context of Babylonian exile; names absorbed from the surrounding culture while the covenant community maintained its identity. The NT church similarly exists within cultures that shape its language and names, while its ultimate identity is defined by belonging to Christ rather than by ethnic or cultural purity.</p>',
    "20": '<p>A theme: the descendants of Adin, 655 — the name means &#8220;dainty, delicate.&#8221; The preservation of smaller, less prominent clans in the official register reflects YHWH&#8217;s comprehensive care for his people; no family is too small to be counted. Christ&#8217;s parable of the lost sheep (Luke 15:4-7) makes the same point: the one lost from the ninety-nine is sought specifically, not treated as statistically insignificant.</p>',
    "21": '<p>A theme: the descendants of Ater, that is of Hezekiah, 98 — the connection to Hezekiah&#8217;s name (&#8220;YHWH has strengthened&#8221;) within this clan name links the returning community to the pre-exilic reform king whose faithfulness delayed judgment (2 Kgs 20:6). The smallest clans are anchored to the largest names of covenant history; the NT community similarly traces its identity back to Abraham and David (Matt 1:1), its identity defined by its ancestry in covenant faithfulness.</p>',
    "22": '<p>A theme: the descendants of Hashum, 328 — each returned family is a testimony to YHWH&#8217;s faithfulness in gathering. The cumulative weight of the census is the weight of evidence for divine fidelity: when each family number is added to the previous, the total represents the scope of YHWH&#8217;s action; Christ will gather a people from every tribe and language and nation (Rev 5:9) — a census that will be beyond any counting.</p>',
    "23": '<p>A theme: the descendants of Bezai, 324 — Bezai sealed the covenant in Neh 10:18. The overlap between the census list and the covenant-sealing list signals that those registered in the genealogical record are the same as those who commit to the covenant in ch10; the recorded name and the covenant commitment are two sides of the same identity. In the NT, those written in the Lamb&#8217;s book of life are precisely those who belong to the new covenant in Christ&#8217;s blood (Luke 22:20).</p>',
    "24": '<p>A theme: the descendants of Hariph, 112 — the name means &#8220;autumn rain&#8221; or &#8220;early harvest.&#8221; The agricultural names embedded in clan genealogies connect the covenant people to the land and its rhythms; the exile severed that connection, but the return restores it. Christ describes himself as the one who &#8220;sends rain on the righteous and the unrighteous&#8221; (Matt 5:45) — the God of the harvest season named in this clan is the same God who sends his Son into the harvest (Matt 9:38).</p>',
    "25": '<p>A theme: the people of Gibeon, 95 — Gibeon was the city of the Hivites who made a deceptive covenant with Joshua (Josh 9); their descendants are counted in the return list as Israelites. The inclusion of Gibeonite ancestry within the covenant community&#8217;s census anticipates the NT&#8217;s boundary-crossing: those who were once outside the covenant community are included within it through covenant commitment (Eph 2:12-13).</p>',
    "26": '<p>A theme: the men of Bethlehem and Netophah, 188 — Bethlehem is the city of David&#8217;s birth and of Christ&#8217;s nativity (Matt 2:1; Luke 2:4). Its presence in the return census anchors the restored community in the Davidic geography; the families returning to Bethlehem will be the ancestors of the generation that lives in Bethlehem at the time of the census decreed by Caesar Augustus (Luke 2:1-4). The return to the land is the precondition for the Incarnation.</p>',
    "27": '<p>A theme: the men of Anathoth, 128 — Anathoth was Jeremiah&#8217;s hometown (Jer 1:1); the families returning to Anathoth are returning to the city of the prophet who promised the new covenant (Jer 31:31-34). The community that will rebuild Anathoth and settle there is living in the very place from which the new covenant promise was delivered; they are dwelling in the prophet&#8217;s words before they know how those words will be fulfilled in Christ.</p>',
    "28": '<p>A theme: the men of Beth-azmaveth, 42 — a small village return. Even the most modest resettlements are recorded in YHWH&#8217;s census; the comprehensive accounting reflects the divine commitment to the whole covenant community, not just its prominent members. The NT&#8217;s corresponding census is of those whose names are written before the foundation of the world (Rev 13:8; Eph 1:4) — a register that includes each person regardless of prominence.</p>',
    "29": '<p>A theme: Kiriath-jearim, Chephirah, and Beeroth, 743 — Kiriath-jearim was where the ark of the covenant rested for twenty years (1 Sam 7:1-2) before David brought it to Jerusalem (2 Sam 6:2). The families returning to Kiriath-jearim are returning to the place of the ark&#8217;s long resting; Christ is the true ark of the covenant in whom the divine presence dwells bodily (Col 2:9; John 1:14).</p>',
    "30": '<p>A theme: the men of Ramah and Geba, 621 — Ramah was Samuel&#8217;s home, school, and burial place (1 Sam 25:1); the families returning to Ramah inhabit the city of the last judge and first king-maker. The restoration of the prophetic-covenant city is part of the reconstitution of the full pre-exilic geography; Christ, who is prophet, priest, and king simultaneously, fulfills all three roles that the Ramah tradition shaped.</p>',
    "31": '<p>A theme: the men of Michmas, 122 — Michmash was the scene of Jonathan&#8217;s single-handed victory against the Philistines (1 Sam 13-14), one of the OT&#8217;s great faith-combat narratives. The return of a community to Michmash restores human presence to a place of covenant faithfulness; the NT builds on this tradition of the single faithful person whose trust in YHWH achieves what an army could not.</p>',
    "32": '<p>A theme: the men of Bethel and Ai, 123 — Bethel is the site of Jacob&#8217;s dream (Gen 28:10-17), where the ladder between heaven and earth was revealed; Jesus explicitly identifies himself as the fulfillment of that vision (John 1:51: &#8220;you will see heaven open, and the angels of God ascending and descending on the Son of Man&#8221;). The families returning to Bethel are returning to the place of the vision that Christ claims as his own self-description.</p>',
    "33": '<p>A theme: the men of the other Nebo, 52 — Nebo was the mountain from which Moses saw the promised land he could not enter (Deut 34:1); the &#8220;other Nebo&#8221; is a town, not the mountain, but the name carries the memory of Moses&#8217; incomplete entry. The incompleteness of Moses&#8217; entrance points forward to Christ, who enters the promised rest that Moses could not: &#8220;God had planned something better for us so that only together with us would they be made perfect&#8221; (Heb 11:40).</p>',
    "34": '<p>A theme: the other descendants of Elam, 1,254 — a second Elam family group with identical count to the first (v.12). The repetition within the list may reflect parallel registration of the same large clan in different geographical groups; the careful double-registration demonstrates the comprehensiveness of the accounting. YHWH does not miss any of his people, a characteristic fully expressed in Christ&#8217;s declaration: &#8220;I shall lose none of all those he has given me&#8221; (John 6:39).</p>',
    "35": '<p>A theme: the descendants of Harim, 320 — the Harim priestly clan (7:42: 1,017) and the lay Harim clan (7:35: 320) are distinguished by their separate registration; the same family name exists in both priestly and lay branches. The parallel existence of priestly and lay lines within the covenant community anticipates the NT&#8217;s dual fulfillment: all believers are priests (1 Pet 2:9) while Christ is the singular high priest (Heb 4:14).</p>',
    "36": '<p>A theme: the descendants of Jericho, 345 — returning to Jericho, the first conquered city (Josh 6), whose walls famously fell. The wall-rebuilders of Nehemiah come from the city whose walls needed no human labor to fall; the contrast underlines the different modes of divine action: Jericho&#8217;s walls fell through obedient faith, Jerusalem&#8217;s rose through obedient labor. Both express the same covenant faithfulness that Christ embodies in his incarnation: taking up human work to accomplish divine redemption.</p>',
    "37": '<p>A theme: the descendants of Lod, Hadid, and Ono, 721 — Lod (also called Lydda in the NT) is the city where Peter healed Aeneas (Acts 9:32-35), the healing that led to the Joppa revival. The families returning to Lod inhabit the city where NT mission will demonstrate the continuing power of YHWH to restore his people; the same divine faithfulness that returned these families from exile will raise Aeneas from his bed two generations later.</p>',
    "38": '<p>A theme: the descendants of Senaah, 3,930 — the largest single lay clan count in the list. Their great number signals that ordinary families, not just priestly or noble clans, form the majority of the returning community. The NT church is similarly constituted: &#8220;not many were wise by human standards; not many were influential; not many were of noble birth&#8221; (1 Cor 1:26) — the community of the returned is the community of ordinary people gathered by divine grace.</p>',
    "39": '<p>A theme: the priestly descendants of Jedaiah, 973 — the priests are registered separately from the lay clans, signaling the continuation of the Aaronic priestly institution after the exile. Hebrews explicitly engages this institution: &#8220;if perfection could have been attained through the Levitical priesthood... why was there still need for another priest to come?&#8221; (Heb 7:11). The restoration of the Aaronic priesthood is the precise institution that Hebrews will argue is insufficient and surpassed by the Melchizedekian priesthood of Christ.</p>',
    "40": '<p>A theme: the descendants of Immer, 1,052 — Immer is one of the four returning priestly families (alongside Jedaiah, Pashur, and Harim). The Immer family is prominent in the pre-exilic period (Jer 20:1: Pashur son of Immer, the priest who had Jeremiah beaten). The same priestly families that opposed the pre-exilic prophets now return to rebuild the prophesied restoration; the tension between prophetic word and priestly institution will find its resolution in Christ, who is both prophet and priest.</p>',
    "41": '<p>A theme: the descendants of Pashur, 1,247 — the Pashur who put Jeremiah in the stocks (Jer 20:1) bore this priestly family name; his descendants are in the return census. The families whose ancestors opposed the prophetic word now serve in the rebuilt temple. The NT makes a parallel point: the same Sanhedrin that crucified Jesus contains both those who become disciples (Nicodemus, Joseph of Arimathea) and those who remain in opposition; priestly descent does not determine individual response to the divine word.</p>',
    "42": '<p>A theme: the descendants of Harim, 1,017 — the largest single priestly family in the return. Harim&#8217;s priest-children are among those who contracted foreign marriages that Ezra required them to dissolve (Ezra 10:21); the priestly family most numerous in the census was also most heavily implicated in the covenant compromise. The NT applies the same pattern: the one with the greatest privilege bears the greatest responsibility (Luke 12:48); the priestly institution&#8217;s failure to maintain covenant purity is exactly what Christ&#8217;s definitive priesthood replaces.</p>',
    "43": '<p>A theme: the Levites, descendants of Jeshua through Kadmiel and Hodevah, 74 — the Levites are strikingly few compared to the priestly count (4,289 priests vs. 74 Levites). This scarcity of Levites was a recurring problem (Ezra 8:15-20); Levitical ministry was difficult, low-status, and poorly supported. The NT applies the same ministry-support logic that Nehemiah addresses: &#8220;The Lord commanded that those who proclaim the gospel should get their living by the gospel&#8221; (1 Cor 9:14; cf. Neh 13:10-13).</p>',
    "44": '<p>A theme: the singers, descendants of Asaph, 148 — the Asaphite singers are the guardians of the musical worship tradition David established. They return to their role in the restored community&#8217;s worship; their function is to give voice to the community&#8217;s praise. Revelation&#8217;s vision of eternal worship (Rev 5:9-10: &#8220;they sang a new song&#8221;) builds on the Asaphite tradition; the song of the redeemed is the eschatological fulfillment of what the return census singers were trained to lead.</p>',
    "45": '<p>A theme: the gatekeepers, descendants of Shallum, Ater, Talmon, Akkub, Hatita, and Shalmai, 138 — the gatekeepers guard access to the holy space. Their function is the earthly analog to the angelic guardianship of the tree of life (Gen 3:24) and the apocalyptic guardianship of the new Jerusalem&#8217;s gates (Rev 21:12-13). Christ identifies himself as the gate (John 10:9), displacing the human gatekeeper institution: he himself controls access to the Father&#8217;s presence.</p>',
    "46": '<p>A theme: the temple servants (nᵉṯînîm), beginning with Ziha, Hashupha, and Tabbaoth — the nᵉṯînîm were the lowest-status temple workers, whose ancestry may have included Canaanite or foreign-captive origins. Their inclusion in the covenant census alongside the priests signals the comprehensive gathering of all who serve the temple. Christ&#8217;s temple community similarly includes those of every background who are given (the root meaning of <em>nāṯan</em>) to his service.</p>',
    "47": '<p>A theme: the descendants of Keros, Sia, and Padon — the continuation of the nᵉṯînîm list. The preservation of these subordinate temple workers&#8217; names in the canonical record reflects the same divine attention to the least-prominent that Christ expresses in his declaration: &#8220;Whoever welcomes this little child in my name welcomes me&#8221; (Luke 9:48). The names of the lowly are in God&#8217;s book.</p>',
    "48": '<p>A theme: the descendants of Lebana, Hagaba, and Shalmai — three more nᵉṯînîm families. The steady continuation of the list without commentary signals the democratic character of the divine census: every name is equally recorded, equally preserved, equally included in the community whose task is to maintain the worship of YHWH. The NT church inherits this egalitarian-before-God principle (Gal 3:28).</p>',
    "49": '<p>A theme: the descendants of Hanan, Giddel, and Gahar — nᵉṯînîm names continuing. Hanan means &#8220;gracious&#8221;; Giddel, &#8220;he has magnified.&#8221; The theophoric elements embedded in even the lowly temple workers&#8217; ancestral names demonstrate that the covenant community is saturated with confessional naming — each name a testimony to a divine attribute. The NT carries this practice forward in the naming of believers as those who are &#8220;blessed with every spiritual blessing&#8221; (Eph 1:3).</p>',
    "50": '<p>A theme: the descendants of Reaiah, Rezin, and Nekoda — the nᵉṯînîm list continues with foreign-sounding names (Rezin is an Aramaic name used by a Syrian king in 2 Kgs 16:5). The presence of originally foreign ancestral names within the covenant community&#8217;s census testifies to the historical reality of the mixed-origin community that gathered around YHWH&#8217;s temple; the NT church&#8217;s inclusion of all nations is the explicit fulfillment of this trajectory (Acts 10:34-35).</p>',
    "51": '<p>A theme: the descendants of Gazzam, Uzza, and Phaseah — more nᵉṯînîm families. Phaseah means &#8220;the limping one&#8221; — a name that preserves a family&#8217;s historical physical characteristic. The divine register preserves not just the dignified names but those that carry the marks of human weakness; Christ, who identifies with the least and the lowest, is the one in whom &#8220;all things hold together&#8221; (Col 1:17) — including the families whose names reflect their vulnerability.</p>',
    "52": '<p>A theme: the descendants of Besai, Meunim, and Nephishesim — Meunim refers to people from Ma&#8217;an (a region southeast of Petra); Nephishesim may connect to the Nephisim, an Ishmaelite tribe (Gen 25:15). The inclusion of nᵉṯînîm with non-Israelite ethnic ancestry in the census of YHWH&#8217;s community is the OT anticipation of Acts 2:5-11 where &#8220;devout Jews from every nation under heaven&#8221; gather at Pentecost — the covenant community has always been broader than pure ethnic descent.</p>',
    "53": '<p>A theme: the descendants of Bakbuk, Hakupha, and Harhur — the continuation of the nᵉṯînîm families; many of these names have no known etymology or appear only in this list. The preservation of names whose meaning is obscure or unknown reflects the character of historical documentation: the divine record keeps what human memory forgets. Rev 2:17 promises each believer &#8220;a white stone with a new name written on it, known only to the one who receives it&#8221; — the personal, particular knowledge of each member of the community.</p>',
    "54": '<p>A theme: the descendants of Bazlith, Mehida, and Harsha — the nᵉṯînîm list nears its end. Harsha means &#8220;deaf&#8221; or &#8220;mute&#8221; — another name that preserves a family&#8217;s ancestral characteristic. The gathering of those whose names reflect limitation anticipates Isaiah&#8217;s messianic sign: &#8220;then the eyes of the blind shall be opened, and the ears of the deaf unstopped&#8221; (Isa 35:5), which Jesus cites as evidence of his identity (Matt 11:5).</p>',
    "55": '<p>A theme: the descendants of Barkos, Sisera, and Tamah — the Sisera name is striking: Sisera was Jabin&#8217;s general killed by Jael (Judg 4:17-22), a Canaanite military leader. A nᵉṯînîm family bearing his name may descend from Canaanite prisoners given to temple service. The presence of Sisera&#8217;s descendants in YHWH&#8217;s temple community is one of the OT&#8217;s most striking enactments of the gospel&#8217;s universal reach; the NT equivalent is Paul&#8217;s declaration that &#8220;in Christ Jesus there is neither Jew nor Greek&#8221; (Gal 3:28).</p>',
    "56": '<p>A theme: the descendants of Neziah and Hatipha — the final two nᵉṯînîm families of the list. The list of these subordinate temple workers is longer than the Levitical list (74 Levites vs. many more nᵉṯînîm families), signaling that the bulk of temple labor was performed by those of the lowest institutional status. Christ&#8217;s kingdom inverts this: &#8220;the greatest among you shall be your servant&#8221; (Matt 23:11); the highest status belongs to the one who serves most, as Christ embodied (Mark 10:45).</p>',
    "57": '<p>A theme: the descendants of Solomon&#8217;s servants, beginning with Sotai, Sophereth, and Perida — a separate category from the nᵉṯînîm; these families&#8217; ancestry traces to the personal servants of Solomon&#8217;s household rather than to priestly temple gifts. Solomon&#8217;s kingdom is the type of Christ&#8217;s kingdom (Matt 12:42; 1 Kgs 10:24); the servants of Solomon&#8217;s household who return to the covenant community anticipate the servants of the greater-than-Solomon who make up his household (Eph 2:19).</p>',
    "58": '<p>A theme: the descendants of Jaala, Darkon, and Giddel — Solomon&#8217;s servants list continues. These families&#8217; institutional identity derived from their ancestors&#8217; service to the Davidic king at the apex of Israel&#8217;s monarchical glory. Their return to Jerusalem after the Solomonic kingdom&#8217;s collapse and exile is a shadow of the gathering of the scattered members of Christ&#8217;s household; scattered by persecution (Acts 8:1), they return to the community centered on the greater David.</p>',
    "59": '<p>A theme: the descendants of Shephatiah, Hattil, Pochereth-hazzebaim, and Amon — the last of Solomon&#8217;s servants. The Solomonic servant-class and the Levitical/priestly class return together; their return is neither ranked by status nor separated by origin. The one community of returned exiles encompasses all institutional roles of the pre-exilic period. This unified return anticipates the NT&#8217;s one body with many members (1 Cor 12:12) — all gifts and roles unified under one head.</p>',
    "60": '<p>A theme: the total of temple servants and Solomon&#8217;s servants, 392 — a small but complete community of temple servants. The precision of &#8220;392&#8221; reflects the same divine attention to exact numbers that characterizes the census throughout; not one servant has been lost from YHWH&#8217;s account. Christ&#8217;s declaration &#8220;I have not lost one of those you gave me&#8221; (John 18:9) is the NT expression of the same divine precision about the completeness of his people.</p>',
    "61": '<p>A theme: those who came from Tel-melah, Tel-harsha, Cherub, Addon, and Immer but could not establish their Israelite lineage — genealogical uncertainty at the census&#8217;s boundary. The five place-names are Babylonian settlement sites for exiled Israelites; families that had been in exile long enough that their genealogical records were lost or disputed. Their uncertain status is noted but they are not excluded from the assembly — only from priestly service.</p>',
    "62": '<p>A theme: the descendants of Delaiah, Tobiah, and Nekoda, 642 — individuals of uncertain Israelite origin registered provisionally within the community. The Tobiah name here (shared with Nehemiah&#8217;s opponent) is coincidental, but the juxtaposition highlights the complexity of identity in the post-exilic community: the name of an enemy also belongs to families within the covenant. The NT equivalent is the warning that &#8220;not everyone who says to me, &#8216;Lord, Lord,&#8217; will enter the kingdom of heaven&#8221; (Matt 7:21) — external identification is not the same as genuine belonging.</p>',
    "63": '<p>A type: priests who could not prove their genealogy were excluded from service — the descendants of Hobaiah, Hakkoz, and Barzillai (who took his wife&#8217;s family name instead of maintaining his priestly lineage). The exclusion from priestly service without genealogical proof illustrates the fundamental limitation of the Aaronic priesthood: it was constituted by biological descent, which could be lost, falsified, or forgotten. Hebrews 7:14 makes the corresponding point about Christ&#8217;s priesthood: it is not constituted by genealogy (Jesus was from Judah, not Levi) but by divine oath (Ps 110:4; Heb 7:20-21) — a basis that cannot be lost or forged.</p>',
    "64": '<p>A type: &#8220;These searched for their names in the genealogical records but could not find them, so they were disqualified from the priesthood as unclean (<em>gōʾālû</em>)&#8221; — the priestly disqualification by unfindable name points to the inverse truth of the gospel: those whose names are found written in the Lamb&#8217;s book of life (Rev 20:15; 21:27) are never disqualified; Christ is the priest who intercedes for all whose names he carries, and none will be found missing. The Aaronic census&#8217;s missing names anticipate the NT&#8217;s promise that no name written in the book of life will be lost.</p>',
    "65": '<p>A type: &#8220;The governor told them they were not to eat any of the most holy food until a priest appeared who could consult the Urim and Thummim&#8221; — the suspension of priestly function awaiting the Urim and Thummim is the post-exilic community&#8217;s frank acknowledgment that the definitive means of divine discernment was missing. Nehemiah 7:65 effectively says: the question cannot be resolved now; a future priest with full divine discernment must settle it. Hebrews identifies that future priest as Christ: he is the high priest who knows the hearts of all, needing no external discernment tool (Heb 4:13; 7:25), the one before whom all things are &#8220;naked and exposed.&#8221;</p>',
    "66": '<p>A theme: the whole assembly together numbered 42,360 — the total count of the returning community. The round number 42,360 appears in both Ezra 2:64 and here; the discrepancy in detail lists (Ezra counts 49,897, Nehemiah counts approximately 31,089) suggests different counting methods for subgroups. The grand total is consistent: the whole assembly is of one piece, a single covenant community. The NT&#8217;s corresponding totality is the &#8220;church&#8221; (<em>ekklesia</em>), which in its broadest sense is the full number of the elect from all ages (Eph 1:22-23).</p>',
    "67": '<p>A theme: 7,337 servants and 245 male and female singers, in addition to the 42,360 — the full community includes those beyond the core census; the broader household accompanies the registered Israelites. The inclusion of both male and female singers in the community&#8217;s travel mirrors the NT community&#8217;s inclusion of all categories: &#8220;there is neither Jew nor Greek, slave nor free, male and female, for you are all one in Christ Jesus&#8221; (Gal 3:28).</p>',
    "68": '<p>A theme: 736 horses and 245 mules — the census extends to the animals of the community. The practical dimension of the return (transportation, agricultural animals) reflects the material reality of covenant community life; the OT&#8217;s concern for animals (Deut 25:4; Prov 12:10) is not incidental but reflects the Creator&#8217;s comprehensive care for his creation, which the NT presents as cosmic in scope (Rom 8:19-21: creation itself awaits the redemption of God&#8217;s children).</p>',
    "69": '<p>A theme: 435 camels and 6,720 donkeys — the donkey count is by far the largest; donkeys were the primary work and transport animal of the ancient Near East. The humble donkey figures prominently in the biblical narrative from Abraham&#8217;s journey to Mount Moriah (Gen 22:3) through to Christ&#8217;s triumphal entry (Matt 21:5; Zech 9:9): the king who comes riding on a donkey is the fulfillment of both Israel&#8217;s patriarchal journey and her eschatological hope.</p>',
    "70": '<p>A theme: the governor (Nehemiah) contributed 1,000 gold darics, 50 basins, and 530 priestly garments to the treasury. The leader&#8217;s freewill contribution to the covenant community&#8217;s restoration anticipates Paul&#8217;s description of Christ&#8217;s self-giving: &#8220;you know the grace of our Lord Jesus Christ, that though he was rich, yet for your sake he became poor, so that you through his poverty might become rich&#8221; (2 Cor 8:9); the community&#8217;s leader contributes first and most.</p>',
    "71": '<p>A theme: family heads give 20,000 gold darics and 2,200 minas of silver — generous voluntary contribution by the lay leadership. The freewill offering character of these contributions (as opposed to mandatory taxation) reflects the covenant principle of joyful generosity; &#8220;God loves a cheerful giver&#8221; (2 Cor 9:7) — the post-exilic community&#8217;s contributions to the restoration fund are the OT form of the NT&#8217;s theology of generous giving from the overflow of grace.</p>',
    "72": '<p>A theme: the people give 20,000 gold darics, 2,000 minas of silver, and 67 priestly garments — the ordinary community matches the family heads&#8217; contribution. The people&#8217;s giving is proportional to the leaders&#8217;; the whole community participates in funding the restoration. The NT applies the same principle: &#8220;Each person should give what they have decided in their heart to give&#8221; (2 Cor 9:7); the covenant community&#8217;s restoration is a project of the whole assembly, not of a wealthy elite.</p>',
    "73": '<p>A theme: the priests, Levites, gatekeepers, singers, temple servants, and all Israel settled in their towns — the comprehensive settlement of the covenant community in its proper places. The seventh month&#8217;s arrival is the narrative hinge: Nehemiah 8 begins &#8220;when the seventh month came,&#8221; connecting the settlement to the great Torah reading that follows. The settled community is the prerequisite for the Word to be publicly proclaimed; the church&#8217;s order and stability is the context in which the Scriptures can be opened for all to hear (1 Tim 2:2).</p>',
  },
  "8": {
    "1": '<p>A type: all the people gather &#8220;as one&#8221; (<em>kᵉʾîš ʾeḥāḏ</em> — literally &#8220;as one man&#8221;) in the square before the Water Gate to hear the Book of the Law — the unity of the assembled community to receive the divine word. This is the most explicitly word-centered assembly in the OT: the people themselves ask for the Torah to be read; the initiative is theirs. Christ declares &#8220;Blessed are those who hunger and thirst for righteousness&#8221; (Matt 5:6); the Water Gate assembly is the OT form of that hunger.</p>',
    "2": '<p>A type: Ezra brings the Law before men, women, and &#8220;all who were old enough to understand&#8221; on the first day of the seventh month (the Feast of Trumpets). The inclusive audience — not just the literate or the priestly — anticipates the NT&#8217;s democratic proclamation of the word. Luke 4:16-21: Jesus reads the Isaiah scroll in the synagogue to a similarly inclusive audience and declares fulfillment in their hearing; the Water Gate reading and the Nazareth reading are structurally parallel: the authoritative text read, meaning given, the people respond.</p>',
    "3": '<p>A type: six hours of public Torah reading from early morning until noon — the sustained attention of the whole community to the word of God. The people &#8220;listened attentively&#8221; (<em>ʾoznê kāl-hāʿām ʾel-sēper hattôrāh</em>, literally &#8220;all the people&#8217;s ears were toward the Book of the Law&#8221;). The posture of collective attention to the word is the OT form of Christ&#8217;s declaration that &#8220;whoever has ears to hear, let them hear&#8221; (Matt 11:15); the attentiveness of the Water Gate congregation is the model for the hearing that the gospel demands.</p>',
    "4": '<p>A type: Ezra stands on a wooden platform (<em>migdāl ʿēṣ</em>, a &#8220;tower of wood&#8221;) built for the occasion — the first dedicated preaching platform in Jewish history, constructed specifically to elevate the reader of the word above the people so all could see and hear. The six assistants on his right and seven on his left represent both the priestly validation of the reading and the communal support for the ministry of the word. Paul&#8217;s description of the preacher&#8217;s authority (1 Cor 1:21; Rom 10:14-15) builds on this tradition of the authorized public reader/expositor.</p>',
    "5": '<p>A type: when Ezra opened the book, &#8220;everyone stood up&#8221; — the congregation&#8217;s spontaneous rising to honor the word. The reverence shown to the Torah scroll is the physical expression of the conviction that when the word of God is opened and read, YHWH himself is present and speaking. The NT narrows this conviction to Christ as the Word (John 1:1-14): the reverence that the Water Gate congregation showed to the scroll is the reverence that the NT community is called to show to Christ, in whom the word is enfleshed.</p>',
    "6": '<p>A type: &#8220;Amen! Amen!&#8221; with lifted hands and prostration — the congregation&#8217;s double affirmation of the word and worship. The double &#8220;Amen&#8221; before the reading (not after) is the community&#8217;s pre-emptive agreement with whatever the word will say; the prostration (<em>wayyiqqᵉḏû wayyišṯaḥᵃwû</em>) is total surrender. Revelation applies this double-Amen to Christ himself (Rev 3:14: &#8220;these are the words of the Amen, the faithful and true witness&#8221;) — Christ is himself the &#8220;Amen&#8221; to all of God&#8217;s promises (2 Cor 1:20).</p>',
    "7": '<p>A type: the thirteen Levites help the people &#8220;understand (<em>mᵉḇînîm</em>) the Law, while the people remained standing in their places&#8221; — the explanatory ministry alongside the public reading. The Levites move among the standing congregation giving the interpretation that enables understanding; this is the origin of the synagogue homily tradition that shaped Jewish education and is the direct context for Jesus&#8217; reading and teaching in Nazareth (Luke 4:16-21). The interpretive ministry that makes the word accessible is part of YHWH&#8217;s provision for his people.</p>',
    "8": '<p>A direct type: &#8220;They gave the meaning (<em>wᵉśôm śekel</em>), so that the people understood (<em>wayyāḇînû</em>) what was being read&#8221; — the explanatory word that produces understanding. This is the precise act that Luke 24:45 describes for Christ: &#8220;he opened their minds so they could understand the Scriptures.&#8221; The Levites&#8217; act at the Water Gate is the institutional type; Christ&#8217;s act in the upper room is the fulfillment. The difference: the Levites explained what Moses wrote; Christ opened the understanding to see that Moses wrote about him (John 5:46).</p>',
    "9": '<p>A type: the people weep as they hear the words of the Law — the word of God produces godly grief before it produces joy; the Torah reading reveals the gap between what the community has been and what YHWH requires. &#8220;Godly grief produces a repentance that leads to salvation without regret, whereas worldly grief produces death&#8221; (2 Cor 7:10); the Water Gate congregation&#8217;s tears are the OT form of the NT&#8217;s repentance-before-rejoicing pattern. The Beatitude &#8220;blessed are those who mourn, for they will be comforted&#8221; (Matt 5:4) describes exactly this movement.</p>',
    "10": '<p>A direct theme: &#8220;The joy of the LORD is your strength&#8221; (<em>ḥeḏwaṯ YHWH hî māʿuzzᵉḵem</em>) — Nehemiah&#8217;s declaration to the weeping community. The reversal from grief to joy is the gospel pattern: conviction leads to repentance, repentance to the declaration of holiness, holiness to joy. Christ declares the same movement in John 15:11: &#8220;I have told you this so that my joy may be in you and that your joy may be complete.&#8221; The joy of the Water Gate assembly comes from understanding the word; the NT joy comes from understanding that the Word has become flesh and dwells among us (John 1:14).</p>',
    "11": '<p>A theme: the Levites quiet the people, saying &#8220;Hush! This day is holy. Do not grieve&#8221; — the pastoral response to the grief that the word has produced; the authorized interpreters of the word also manage the community&#8217;s emotional response to it. The movement from grief to silence to joy mirrors the liturgical progression that the NT describes for encountering God&#8217;s holiness (Isa 6:5-7: Isaiah&#8217;s fear, purification, and commissioning); the Levites&#8217; &#8220;hush&#8221; is the OT equivalent of the divine purification that transforms grief into readiness for service.</p>',
    "12": '<p>A theme: all the people went to eat, drink, share food, and &#8220;celebrate with great joy, because they now understood the words that had been explained to them&#8221; — understanding of the word is the specific ground of the joy. The joy is not circumstantial but cognitive: they understand what was hidden. The NT makes the same connection: &#8220;How beautiful are the feet of those who bring good news!&#8221; (Rom 10:15); the messenger who brings understanding produces the joy that the Water Gate community experiences. The feast of ch8:12 anticipates the great supper of the Lamb (Rev 19:9).</p>',
    "13": '<p>A type: on the second day, the heads of families, priests, and Levites gather specifically to &#8220;study the words of the Law with Ezra the scribe&#8221; — a second tier of engagement: the general public hearing is followed by the leadership&#8217;s intensive study. The two-level approach (public proclamation + intimate study) anticipates Christ&#8217;s ministry pattern: public teaching to crowds, then private explanation to disciples (Matt 13:10-11, 36). The community&#8217;s leaders go deeper into what the people heard on the surface.</p>',
    "14": '<p>A type: in the study they discover the forgotten command to celebrate the Feast of Booths (Sukkoth) in the seventh month. The word of God, when studied carefully, reveals what the community had neglected; the same pattern appears in Josiah&#8217;s discovery of the Torah scroll (2 Kgs 22:8-11). Christ&#8217;s teaching similarly recovers the original intent behind commands that tradition had obscured: &#8220;You have heard it said... but I tell you&#8221; (Matt 5:21-22); the word rediscovered challenges the community&#8217;s settled patterns.</p>',
    "15": '<p>A type: the proclamation goes out to all the towns: &#8220;Go out to the hill country and bring back branches of olive, wild olive, myrtle, palm, and other leafy trees to make shelters, as it is written.&#8221; The active obedience to the rediscovered word — mobilizing the whole community to build shelters from the specific materials the Torah specifies — is the OT pattern of &#8220;do whatever he tells you&#8221; (John 2:5). The literal fulfillment of the shelters command points forward to the fulfillment of all commands in Christ (Matt 5:17).</p>',
    "16": '<p>A type: the people build shelters on their rooftops, courtyards, in the temple courts, and in the public squares — the Feast of Booths fills Jerusalem&#8217;s entire space with temporary dwelling structures. The pervasiveness of the booths is the pervasiveness of the festival&#8217;s theological claim: YHWH tabernacled with Israel in the wilderness, and the feast remembers that divine dwelling. John 1:14 uses the same vocabulary: &#8220;the Word became flesh and tabernacled (<em>eskēnōsen</em>) among us&#8221; — Christ is the ultimate fulfillment of the Booths festival&#8217;s theological memory.</p>',
    "17": '<p>A fulfillment: &#8220;From the days of Joshua son of Nun until that day, the Israelites had not celebrated this way. And there was very great joy&#8221; — the Feast of Booths had not been properly observed since the conquest, over 900 years earlier. The joy of the restoration is the joy of a recovered identity; the community discovers what it was meant to be. John 7:37-38: Jesus stands at the Feast of Booths and cries out &#8220;let anyone who is thirsty come to me and drink... rivers of living water will flow from within them&#8221; — the feast that the returned community observed with great joy is the feast at which Jesus declares himself the fulfillment of its central symbol (the water-pouring ceremony).</p>',
    "18": '<p>A type: Ezra reads from the Book of the Law daily for the seven days of the feast, with a solemn assembly on the eighth day — the daily word accompanies the daily dwelling in booths; word and life are integrated for the duration of the festival. The eighth day&#8217;s solemn assembly (<em>ʿᵃṣeret</em>) is the completion of the festival cycle; the eighth day in Jewish thought carries connotations of the new beginning (circumcision on the eighth day; the eighth day as the &#8220;first day&#8221; of the new week). Christ&#8217;s resurrection on the first day of the week is the &#8220;eighth day&#8221; that the solemn assembly anticipates: the new creation that begins after the completion of the covenant festival.</p>',
  }
}

def main():
    existing = load_comm('mkt-christ', 'nehemiah')
    merge_comm(existing, NEHEMIAH)
    save_comm('mkt-christ', 'nehemiah', existing)
    print('Nehemiah 7-8 mkt-christ written.')

if __name__ == '__main__':
    main()
